mapper.select:
SELECT r2.ARTICLE_ID AS articleId, COUNT(DISTINCT r2.USER_ID) AS coCount FROM ARTICLE_USER_READS r1 JOIN ARTICLE_USER_READS r2 ON r1.ARTICLE_ID = r2.ARTICLE_ID AND r1.USER_ID != r2.USER_ID WHERE r1.USER_ID = #{userId} AND r1.DEL_FLAG = 0 AND r2.DEL_FLAG = 0
AND r2.ARTICLE_ID NOT IN #{id}
GROUP BY r2.ARTICLE_ID HAVING coCount >= 1 ORDER BY coCount DESC LIMIT #{limit}

SELECT f2.ARTICLE_ID AS articleId, COUNT(DISTINCT f2.USER_ID) AS coCount FROM ARTICLE_FAVORITES f1 JOIN ARTICLE_FAVORITES f2 ON f1.ARTICLE_ID = f2.ARTICLE_ID AND f1.USER_ID != f2.USER_ID WHERE f1.USER_ID = #{userId} AND f1.IS_ACTIVE = 1 AND f1.DEL_FLAG = 0 AND f2.IS_ACTIVE = 1 AND f2.DEL_FLAG = 0
AND f2.ARTICLE_ID NOT IN #{id}
GROUP BY f2.ARTICLE_ID ORDER BY coCount DESC LIMIT #{limit}

SELECT a.ARTICLE_ID AS articleId, a.TITLE AS title, a.SUMMARY AS summary,
       a.COVER_IMAGE_ID AS coverImageId, a.CATEGORY AS category,
       a.VIEW_COUNT AS viewCount, a.FAVORITE_COUNT AS favoriteCount,
       a.PUBLISHED_AT AS publishedAt, e.TEXT_FINGERPRINT AS textFingerprint
FROM ARTICLES a
LEFT JOIN ARTICLE_EMBEDDINGS e ON e.ARTICLE_ID = a.ARTICLE_ID
WHERE a.DEL_FLAG = 0 AND a.STATUS = 3 AND a.ARTICLE_ID != #{articleId}
  AND a.CATEGORY = #{category}
ORDER BY a.VIEW_COUNT DESC, a.PUBLISHED_AT DESC
LIMIT #{limit}
